function a(r){return String(r??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;")}function p(r){return r.replace(/\*\*(.+?)\*\*/g,"<strong>$1</strong>").replace(/__(.+?)__/g,"<strong>$1</strong>").replace(new RegExp("(^|[^\\*])\\*(?!\\s)(.+?)(?<!\\s)\\*","g"),"$1<em>$2</em>").replace(new RegExp("(^|[^_])_(?!\\s)(.+?)(?<!\\s)_","g"),"$1<em>$2</em>")}function c(r){if(!r)return"";const t=String(r).trim();return t?t.split(/\n{2,}/).map(e=>e.trim()).filter(Boolean).map(e=>{const n=a(e).replace(/\n/g,"<br>");return`<p>${p(n)}</p>`}).join(""):""}export{c as r};
